#include <iostream>
using namespace std;

// Abstract Base Class
class Shape {
public:
 // Pure virtual functions - must be overridden
 virtual double area() = 0;
 virtual double perimeter() = 0;

 // Virtual destructor - essential for proper cleanup
 virtual ~Shape() {
 cout << "Shape destructor called" << endl;
 }
};

// Derived Class: Circle
class Circle : public Shape {
private:
 double radius;
public:
 Circle(double r) : radius(r) {}

 // Override pure virtual functions
 double area() override {
 return 3.14159 * radius * radius;
 }

 double perimeter() override {
 return 2 * 3.14159 * radius;
 }

 ~Circle() {
 cout << "Circle destructor called" << endl;
 }
};

// Derived Class: Rectangle
class Rectangle : public Shape {
private:
 double length, width;
public:
 Rectangle(double l, double w) : length(l), width(w) {}

 double area() override {
 return length * width;
 }

 double perimeter() override {
 return 2 * (length + width);
 }

 ~Rectangle() {
 cout << "Rectangle destructor called" << endl;
 }
};

int main() {
 // Cannot instantiate abstract class
 // Shape s; // Error!

 // Use polymorphism through pointers
 Shape* shapes[2];
 shapes[0] = new Circle(5.0);
 shapes[1] = new Rectangle(4.0, 6.0);

 for (int i = 0; i < 2; i++) {
 cout << "Area: " << shapes[i]->area() << endl;
 cout << "Perimeter: " << shapes[i]->perimeter() << endl;
 }

 // Proper cleanup with virtual destructor
 for (int i = 0; i < 2; i++) {
 delete shapes[i];
 }

 return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
 int baseData;
 Base(int b) : baseData(b) {}
 virtual void display() {
 cout << "Base: " << baseData << endl;
 }
 virtual ~Base() {}
};

class Derived : public Base {
public:
 int derivedData;
 Derived(int b, int d) : Base(b), derivedData(d) {}

 void display() override {
 cout << "Base: " << baseData << ", Derived: " << derivedData << endl;
 }
};

void showByValue(Base obj) {
 // Object slicing occurs here - derived portion is lost
 obj.display();
}

void showByReference(const Base& obj) {
 // No slicing - polymorphism works
 obj.display();
}

void showByPointer(const Base* obj) {
 // No slicing - polymorphism works
 obj->display();
}

int main() {
 Derived obj(10, 20);

 cout << "Original object:" << endl;
 obj.display();

 cout << "\nPassing by value (slicing occurs):" << endl;
 showByValue(obj); // Only Base::display() called

 cout << "\nPassing by reference (no slicing):" << endl;
 showByReference(obj); // Derived::display() called

 cout << "\nPassing by pointer (no slicing):" << endl;
 showByPointer(&obj); // Derived::display() called

 return 0;
}

#include <iostream>
#include <string>
using namespace std;

// Abstract Product Interface
class Product {
public:
 virtual string getName() = 0;
 virtual double getPrice() = 0;
 virtual ~Product() {}
};

// Concrete Product: Laptop
class Laptop : public Product {
private:
 string brand;
 double price;
public:
 Laptop(string b, double p) : brand(b), price(p) {}

 string getName() override {
 return brand + " Laptop";
 }

 double getPrice() override {
 return price;
 }
};

// Concrete Product: Phone
class Phone : public Product {
private:
 string brand;
 double price;
public:
 Phone(string b, double p) : brand(b), price(p) {}

 string getName() override {
 return brand + " Phone";
 }

 double getPrice() override {
 return price;
 }
};

// Factory Class
class ProductFactory {
public:
 enum ProductType {
 LAPTOP,
 PHONE
 };

 // Factory method using pure virtual function concept
 static Product* createProduct(ProductType type, string brand, double price) {
 switch(type) {
 case LAPTOP:
 return new Laptop(brand, price);
 case PHONE:
 return new Phone(brand, price);
 default:
 return nullptr;
 }
 }
};

int main() {
 // Client code doesn't know exact class being created
 Product* p1 = ProductFactory::createProduct(ProductFactory::LAPTOP, "Dell", 50000);
 Product* p2 = ProductFactory::createProduct(ProductFactory::PHONE, "Apple", 80000);

 cout << "Product: " << p1->getName() << ", Price: " << p1->getPrice() << endl;
 cout << "Product: " << p2->getName() << ", Price: " << p2->getPrice() << endl;

 delete p1;
 delete p2;

 return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
 // Pure virtual function with default implementation
 virtual void display() = 0;

 // Virtual destructor
 virtual ~Base() {}
};

// Provide implementation for pure virtual function
void Base::display() {
 cout << "Base class default implementation" << endl;
}

class Derived1 : public Base {
public:
 // Override and provide own implementation
 void display() override {
 cout << "Derived1 custom implementation" << endl;
 }
};

class Derived2 : public Base {
public:
 // Use base class default implementation
 void display() override {
 // Call base class implementation
 Base::display();
 }
};

int main() {
 Derived1 d1;
 Derived2 d2;
 Base* ptr;

 ptr = &d1;
 ptr->display(); // Calls Derived1::display()

 ptr = &d2;
 ptr->display(); // Calls Derived2 which calls Base::display()

 return 0;
}
